stats.proof_process_SucAdd:
match y
  case Zero =>
    // LHS: Suc(Add(x, Zero)) == Suc(x)
    // RHS: Add(Suc(x), Zero) == Suc(x)
    // Both sides reduce to Suc(x) by definition of Add.
  case Suc(y') =>
    calc {
      Suc(Add(x, Suc(y')));
    ==  // def. Add
      Suc(Suc(Add(x, y')));
    ==  { SucAdd(x, y'); }
      Suc(Add(Suc(x), y'));
    ==  // def. Add (in reverse)
      Add(Suc(x), Suc(y'));
    }

