stats.proof_process_sum_plus:
if i == 0 {
    // sum(s, 0) = 0 and sum(s, 1) = s[0] + sum(s[1..], 0) = s[0]
    // So 0 + s[0] == s[0], which is trivial.
} else {
    // Both sides unfold since i > 0:
    // sum(s, i) = s[0] + sum(s[1..], i-1)
    // sum(s, i+1) = s[0] + sum(s[1..], i)
    // We need: sum(s[1..], i-1) + s[i] == sum(s[1..], i)
    // Note that s[1..][i-1] == s[i], so the inductive call gives us exactly this.
    sum_plus(s[1..], i-1);
}

