stats.proof_process_DivModIsUnique:
if a == 0 {
      assert n == b;
    } else {
      assert a >= 1 by {
        if a < 0 {
          assert a * m <= -m;
          assert n == a * m + b <= -m + b < 0;
          assert false;
        }
      }
      assert n - m == (a - 1) * m + b by {
        assert a * m + b - m == (a - 1) * m + b;
      }
      assert n - m >= 0 by {
        assert a >= 1;
        assert a * m >= m;
        assert n == a * m + b >= m;
      }
      DivModIsUnique(n - m, m, a - 1, b);
      assert (n - m) / m == a - 1;
      assert (n - m) % m == b;
      DivModAddDenominator(n - m, m);
      assert (n - m + m) / m == (n - m) / m + 1;
      assert (n - m + m) % m == (n - m) % m;
      assert n - m + m == n;
    }

