        case Append(head1, tail1) => match l2
            case Nil => {
                assert Concatenation(l1, Nil) == l1;
                assert Size(Nil) == Zero;
                assert Add(Size(l1), Zero) == Size(l1);
            }
            case Append(_, _) => {
                SizeOfConcatenationIsSumOfSizes(tail1, l2);
                // IH: Size(Concatenation(tail1, l2)) == Add(Size(tail1), Size(l2))

                assert Size(Concatenation(l1, l2))
                    == Size(Append(head1, Concatenation(tail1, l2)))
                    == S(Size(Concatenation(tail1, l2)))
                    == S(Add(Size(tail1), Size(l2)));

                // Need: S(Add(Size(tail1), Size(l2))) == Add(S(Size(tail1)), Size(l2))
                // i.e., S(Add(Size(tail1), Size(l2))) == Add(Size(l1), Size(l2))
                // Add recurses on 2nd arg, so Add(S(Size(tail1)), Size(l2)) 
                // Use commutativity: Add(S(Size(tail1)), Size(l2)) == Add(Size(l2), S(Size(tail1)))
                //                  = S(Add(Size(l2), Size(tail1))) = S(Add(Size(tail1), Size(l2)))

                AddCommutative(Size(tail1), Size(l2));
                // Add(Size(tail1), Size(l2)) == Add(Size(l2), Size(tail1))

                AddCommutative(S(Size(tail1)), Size(l2));
                // Add(S(Size(tail1)), Size(l2)) == Add(Size(l2), S(Size(tail1)))

                assert Add(Size(l2), S(Size(tail1))) == S(Add(Size(l2), Size(tail1)));

                assert Add(Size(l1), Size(l2))
                    == Add(S(Size(tail1)), Size(l2))
                    == S(Add(Size(tail1), Size(l2)));
            }

