stats.proof_process_sumSerie_Lemma:
if n == 0 {
      calc {
         (1-x) * sumSerie(x, 0);
         ==
         (1-x) * 1;
         ==
         1 - x;
         ==
         1 - x * exp(x, 0);
         ==
         1 - exp(x, 1);
         ==
         1 - exp(x, n+1);
      }
   } else {
      sumSerie_Lemma(x, n-1);
      assert (1-x) * sumSerie(x, n-1) == 1 - exp(x, n); // IH
      calc {
         (1-x) * sumSerie(x, n);
         ==
         (1-x) * (sumSerie(x, n-1) + exp(x, n));
         ==
         (1-x) * sumSerie(x, n-1) + (1-x) * exp(x, n);
         == { assert (1-x) * sumSerie(x, n-1) == 1 - exp(x, n); } // IH
         1 - exp(x, n) + (1-x) * exp(x, n);
         ==
         1 - exp(x, n) + exp(x, n) - x * exp(x, n);
         ==
         1 - x * exp(x, n);
         ==
         1 - exp(x, n+1);
      }
   }

stats.proof_process_expPlus1_Lemma:
if n == 1 {
      calc {
         exp(x+1, 1);
         (x+1) * exp(x+1, 0);
         (x+1) * 1;
         x + 1;
         x * 1 + 1;
         x * exp(x, 0) + 1;
         exp(x, 1) + 1;
      }
   } else {
      expPlus1_Lemma(x, n-1);
      // IH: exp(x+1, n-1) >= exp(x, n-1) + 1
      exp_Lemma(x, n-1);
      // exp(x, n-1) >= 1, so exp(x, n-1) + 1 >= 2 >= 1
      assert exp(x+1, n-1) >= exp(x, n-1) + 1;
      assert exp(x, n-1) + 1 >= 1;
      prod_Lemma(x+1, exp(x+1, n-1), exp(x, n-1) + 1);
      // (x+1) * exp(x+1, n-1) >= (x+1) * (exp(x, n-1) + 1)
      calc >= {
         exp(x+1, n);
         == (x+1) * exp(x+1, n-1);
         (x+1) * (exp(x, n-1) + 1);
         == x * exp(x, n-1) + x + exp(x, n-1) + 1;
         == exp(x, n) + x + exp(x, n-1) + 1;
         >= { exp_Lemma(x, n-1); assert x >= 1; assert exp(x, n-1) >= 1; }
         exp(x, n) + 1;
      }
   }

