            nodeConcat(x, reverseList(reverseList(xs.next)));
            // Apply inductive hypothesis
            nodeConcat(x, xs.next);
            // Reassemble: nodeConcat(Node(xs.val, Null), xs.next) == xs
            == { ConcatExtensionality(xs); }
            xs;
        }
    }

