stats.proof_process_transitiveUnion:
assume forall a :: a in S_1 + S_2 ==> a !in S_1 || a !in S_2;
    forall a, b, c | a in S_1 + S_2 && b in S_1 + S_2 && c in S_1 + S_2 && (a, b) in R_1 + R_2 && (b, c) in R_1 + R_2
        ensures (a, c) in R_1 + R_2
    {
        // relationOnASet tells us: (a,b) in R_1 ==> a in S_1 && b in S_1
        //                          (a,b) in R_2 ==> a in S_2 && b in S_2
        // Disjointness: b cannot be in both S_1 and S_2
        // So if (a,b) in R_1 then b in S_1 and b !in S_2, so (b,c) !in R_2, so (b,c) in R_1
        // Similarly if (a,b) in R_2 then b in S_2 and b !in S_1, so (b,c) !in R_1, so (b,c) in R_2
        if (a, b) in R_1 {
            assert a in S_1 && b in S_1;
            assert b !in S_2;
            // So (b,c) cannot be in R_2 (since b !in S_2)
            assert (b, c) !in R_2;
            assert (b, c) in R_1;
            assert c in S_1;
            assert (a, c) in R_1;
            assert (a, c) in R_1 + R_2;
        } else {
            assert (a, b) in R_2;
            assert a in S_2 && b in S_2;
            assert b !in S_1;
            // So (b,c) cannot be in R_1 (since b !in S_1)
            assert (b, c) !in R_1;
            assert (b, c) in R_2;
            assert c in S_2;
            assert (a, c) in R_2;
            assert (a, c) in R_1 + R_2;
        }
    }

