stats.proof_process_GetLargerPrime:
var q := product(s);
  if exists p :: bound < p <= q && IsPrime(p) {
    p :| bound < p <= q && IsPrime(p);
  } else {
    // In this branch, there are no primes in (bound, q].
    // This means AllPrimes(s, bound) implies AllPrimes(s, q),
    // because any prime p' <= q is either <= bound (hence in s) or in (bound, q] (impossible).
    assert AllPrimes(s, q) by {
      forall x | x in s ensures IsPrime(x) {
        assert AllPrimes(s, bound);
      }
      forall pr | IsPrime(pr) && pr <= q ensures pr in s {
        if pr <= bound {
          assert pr in s;
        } else {
          // pr is in (bound, q] and is prime, contradicting our branch condition
          assert bound < pr <= q && IsPrime(pr);
          assert false;
        }
      }
    }
    ProductPlusOneIsPrime(s, q);
    p := q + 1;
    // Now show bound < p by contradiction
    if p <= bound {
      // p is prime and p <= bound, so p in s
      assert IsPrime(p);
      assert p in s;
      // Every element of s is a prime >= 2, hence >= 1
      assert forall x :: x in s ==> 1 <= x by {
        forall x | x in s ensures 1 <= x {
          assert IsPrime(x);
          assert 2 <= x;
        }
      }
      product_property(s);
