if n == 0 {
    // expo(2, 0) - expo(3, 0) = 1 - 1 = 0
} else if n == 1 {
    assert expo(2, 3) == 8;
    assert expo(3, 1) == 3;
} else {
    // Induction hypothesis
    Expon23(n - 1);
    assert (expo(2, 3 * (n-1)) - expo(3, n-1)) % 5 == 0;

    // Establish expo(2, 3*n) == 8 * expo(2, 3*(n-1))
    // Unroll expo(2, 3*n) three times since 3*n >= 6 when n >= 2
    assert 3 * n >= 6;
    assert 3 * n - 1 >= 5;
    assert 3 * n - 2 >= 4;
    assert expo(2, 3 * n) == 2 * expo(2, 3 * n - 1);
    assert expo(2, 3 * n - 1) == 2 * expo(2, 3 * n - 2);
    assert expo(2, 3 * n - 2) == 2 * expo(2, 3 * n - 3);
    assert 3 * n - 3 == 3 * (n - 1);
    assert expo(2, 3 * n) == 8 * expo(2, 3 * (n - 1));

    // Establish expo(3, n) == 3 * expo(3, n-1)
    assert expo(3, n) == 3 * expo(3, n - 1);

    var A := expo(2, 3 * (n-1));
    var B := expo(3, n - 1);

    // expo(2, 3*n) - expo(3, n) = 8*A - 3*B = 3*(A - B) + 5*A
    assert 8 * A - 3 * B == 3 * (A - B) + 5 * A;

    // By IH, (A - B) % 5 == 0, so 3*(A-B) % 5 == 0
    assert (A - B) % 5 == 0;
    assert (3 * (A - B)) % 5 == 0 by {
        var k := (A - B) / 5;
        assert A - B == 5 * k;
        assert 3 * (A - B) == 5 * (3 * k);
    }

    // 5*A % 5 == 0
    assert (5 * A) % 5 == 0 by {
        assert 5 * A == 5 * A;
    }

    // Sum of two multiples of 5 is multiple of 5
    assert (3 * (A - B) + 5 * A) % 5 == 0 by {
        var j := (3 * (A - B)) / 5;
        assert 3 * (A - B) == 5 * j;
        assert 3 * (A - B) + 5 * A == 5 * (j + A);
    }

    assert (expo(2, 3 * n) - expo(3, n)) == 8 * A - 3 * B;
}

