    // Using large palindrome: s'[c2 + (k+1)] == s'[2c - c2 - (k+1)] = s'[c1 - (k+1)]
    var off1 := c2 + (k+1) - c;
    assert 0 <= off1 <= r;
    lemma_palindromic_radius_contains(s', c, r, off1);
    // So s'[c - off1] == s'[c + off1], i.e., s'[c1 - (k+1)] == s'[c2 + (k+1)]

    // Using large palindrome: s'[c2 - (k+1)] == s'[2c - (c2 - (k+1))] = s'[c1 + (k+1)]
    var off2 := abs(c - (c2 - (k+1)));
    assert off2 == abs(c1 + (k+1) - c);
    assert off2 <= r;
    lemma_palindromic_radius_contains(s', c, r, off2);
    // So s'[c2 - (k+1)] == s'[c1 + (k+1)]

    // From c1's palindrome: s'[c1-(k+1)] == s'[c1+(k+1)]
    lemma_palindromic_radius_contains(s', c1, r1, k+1);

    assert s'[c2 - (k+1)] == s'[c2 + (k+1)];
  }

  if c2 + r1 < c + r {
    // Maximality at r1
    var off_r := c2 + (r1+1) - c;
    assert 0 <= off_r <= r;
    lemma_palindromic_radius_contains(s', c, r, off_r);

    var off_l := abs(c - (c2 - (r1+1)));
    assert off_l == abs(c1 + (r1+1) - c);
    assert off_l <= r;
    lemma_palindromic_radius_contains(s', c, r, off_l);

    assert inbound_radius(s', c1, r1+1) by {
      // c1 - (r1+1) = 2c - c2 - r1 - 1; c2 + r1 + 1 <= c + r so 2c - c2 - r1 - 1 >= c - r >= 0
      // c1 + (r1+1) = 2c - c2 + r1 + 1; c2 - r1 - 1 >= c - r (since c2-r1 > c-r from c1-r1 >= c-r) so c1+(r1+1) <= c+r < |s'|
    }
    assert !palindromic_radius(s', c1, r1 + 1);
    assert s'[c1 - (r1+1)] != s'[c1 + (r1+1)];
    assert s'[c2 - (r1+1)] != s'[c2 + (r1+1)];
    lemma_end_of_expansion(s', c2, r1);
  } else if c2 + r1 > c + r {
    // Maximality at max_mirrored_radius
    if inbound_radius(s', c2, max_mirrored_radius + 1) {
      assert c2 + (max_mirrored_radius + 1) == c + r + 1;

      assert inbound_radius(s', c, r + 1) by {
        assert c + (r+1) == c2 + (max_mirrored_radius + 1) < |s'|;
        assert c - (r+1) >= 0;
      }
      assert !palindromic_radius(s', c, r + 1);
      assert s'[c - (r+1)] != s'[c + (r+1)];

      assert max_mirrored_radius + 1 <= r1;
      lemma_palindromic_radius_contains(s', c1, r1, max_mirrored_radius + 1);
      assert c1 - (max_mirrored_radius + 1) == c - r - 1;
      assert s'[c1 - (max_mirrored_radius+1)] == s'[c1 + (max_mirrored_radius+1)];

      // s'[c2-(mmr+1)] via large palindrome
      var off := abs(c - (c2 - (max_mirrored_radius+1)));
      lemma_palindromic_radius_contains(s', c, r, off);

      assert s'[c2 + (max_mirrored_radius + 1)] == s'[c + r + 1];
      assert s'[c2 - (max_mirrored_radius + 1)] == s'[c1 + (max_mirrored_radius + 1)];
      assert s'[c1 + (max_mirrored_radius + 1)] == s'[c1 - (max_mirrored_radius + 1)];
      assert s'[c1 - (max_mirrored_radius + 1)] == s'[c - (r+1)];
      assert s'[c2 - (max_mirrored_radius + 1)] != s'[c2 + (max_mirrored_radius + 1)];
    }
    lemma_end_of_expansion(s', c2, max_mirrored_radius);
