    // binom(n, m) % 2 == binom(n/2, m/2) % 2

    // Inductive hypothesis
    Lucas_Theorem'(m / 2, n / 2);
    // BitSet(m/2) <= BitSet(n/2) <==> !EVEN(binom(n/2, m/2))

    // Now we need: BitSet(m) <= BitSet(n) <==> BitSet(m/2) <= BitSet(n/2)

    BitSet_Property(m);
    BitSet_Property(n);
    // BitSet(m) - {0} == Suc(BitSet(m/2))
    // BitSet(n) - {0} == Suc(BitSet(n/2))

    SucElements(BitSet(m / 2));
    SucElements(BitSet(n / 2));

    // Show Suc preserves subset relation
    if BitSet(m / 2) <= BitSet(n / 2) {
      // Need to show BitSet(m) <= BitSet(n)
      forall x | x in BitSet(m)
        ensures x in BitSet(n)
      {
        if x == 0 {
          // x == 0 means !EVEN(m), so we need !EVEN(n)
          // In the else branch, !(EVEN(n) && !EVEN(m))
          // Since !EVEN(m), we must have !EVEN(n)
          assert Bit(0, m);
          assert !EVEN(n);
          assert Bit(0, n);
          assert 0 in BitSet(n);
        } else {
          // x > 0, so x in BitSet(m) - {0} == Suc(BitSet(m/2))
          assert x in Suc(BitSet(m / 2));
          // so x-1 in BitSet(m/2) <= BitSet(n/2)
          assert (x - 1) in BitSet(m / 2);
          assert (x - 1) in BitSet(n / 2);
          // so x in Suc(BitSet(n/2)) == BitSet(n) - {0}
          assert x in Suc(BitSet(n / 2));
          assert x in BitSet(n) - {0};
        }
      }
    } else {
      // BitSet(m/2) !<= BitSet(n/2), need to show BitSet(m) !<= BitSet(n)
      // There exists some y in BitSet(m/2) that's not in BitSet(n/2)
