    BetaReduction0(n', h, i);
    BetaReduction0(n', (a: int, b: int) => g(b, a), i);
  }
  Exchange(n', x => Sum(n', y => h(x, y)), x => Sum(n', y => g(y, x)));

  // Inductive hypothesis on h
  CommuteSum(n', h);

  // Exchange for the row/column sums
  forall i | 0 <= i < n'
    ensures (x => h(x, n'))(i) == (x => g(n', x))(i)
  {
  }
  Exchange(n', x => h(x, n'), x => g(n', x));

  forall i | 0 <= i < n'
    ensures (y => h(n', y))(i) == (y => g(y, n'))(i)
