stats.proof_process_InvInductive:
var step :| NextStep(v, v', step);
  match step {
    case CastVoteStep(n, c) => {
      // WF is preserved since votes keys don't change (just the value at n)
      assert v'.WF();

      // Vote uniqueness: n had empty votes, now has {c}; all others unchanged
      forall n', v1, v2 | v1 in v'.votes[n'] && v2 in v'.votes[n']
        ensures v1 == v2
      {
        if n' == n {
          assert v'.votes[n] == {c};
        } else {
          assert v'.votes[n'] == v.votes[n'];
        }
      }

      // Decision unchanged
      assert v'.decision == v.decision;

      // Safety preserved trivially
      assert Safety(v');

      // Decision justification: for each decided choice, the quorum still works
      forall ch | ch in v'.decision
        ensures exists q: Quorum :: ChoiceQuorum(v', q, ch)
      {
        assert ch in v.decision;
        var q0 :| ChoiceQuorum(v, q0, ch);
        forall m | Member(m, q0)
          ensures ch in v'.votes[m]
        {
          assert ch in v.votes[m];
          if m == n {
            // n's old votes were empty, but ch was in v.votes[n], contradiction
            // unless ch == c
            assert v.votes[n] == {};
            assert false;
          } else {
            assert v'.votes[m] == v.votes[m];
          }
        }
        assert ChoiceQuorum(v', q0, ch);
      }
    }
    case DecideStep(c, q) => {
      // WF preserved since votes unchanged
      assert v'.WF();
      assert v'.votes == v.votes;

      // Vote uniqueness preserved since votes unchanged
      forall n', v1, v2 | v1 in v'.votes[n'] && v2 in v'.votes[n']
        ensures v1 == v2
      {
        assert v'.votes[n'] == v.votes[n'];
      }

      // Decision justification
      forall ch | ch in v'.decision
        ensures exists q0: Quorum :: ChoiceQuorum(v', q0, ch)
      {
        if ch in v.decision {
          var q0 :| ChoiceQuorum(v, q0, ch);
          assert ChoiceQuorum(v', q0, ch);
        } else {
          // ch is newly decided, so ch == c
          assert ch == c;
          forall m | Member(m, q)
            ensures c in v'.votes[m]
          {
            assert c in v.votes[m];
          }
          assert ChoiceQuorum(v', q, ch);
        }
      }

      // Safety
      forall c1, c2 | c1 in v'.decision && c2 in v'.decision
        ensures c1 == c2
      {
        if c1 in v.decision && c2 in v.decision {
          assert c1 == c2;
        } else if c1 !in v.decision && c2 !in v.decision {
          assert c1 == c && c2 == c;
        } else if c1 !in v.decision && c2 in v.decision {
          // c1 == c is new, c2 is old
          assert c1 == c;
          var q2 :| ChoiceQuorum(v, q2, c2);
          var n := QuorumIntersect(q, q2);
          assert Member(n, q) && Member(n, q2);
          assert c in v.votes[n];  // from Decide precondition
          assert c2 in v.votes[n]; // from ChoiceQuorum
          // vote uniqueness gives c == c2
          assert c1 == c2;
        } else {
          // c1 is old, c2 == c is new
          assert c2 == c;
          var q1 :| ChoiceQuorum(v, q1, c1);
          var n := QuorumIntersect(q1, q);
          assert Member(n, q1) && Member(n, q);
          assert c1 in v.votes[n];
          assert c in v.votes[n];
          assert c1 == c2;
        }
      }
    }
  }

