            assert seq_sum(s2) == x + seq_sum(remaining2);

            // Show multiset(remaining1) == multiset(remaining2)
            assert s1 == [x] + remaining1;
            assert multiset(s1) == multiset([x]) + multiset(remaining1);

            // Key: decompose s2 as s2_left + [x] + s2_right for multiset reasoning
            assert s2[..i2+1] == s2_left + [x];
            assert s2 == s2[..i2+1] + s2_right;
            assert multiset(s2) == multiset(s2[..i2+1]) + multiset(s2_right);
            assert multiset(s2[..i2+1]) == multiset(s2_left) + multiset([x]);
            assert multiset(s2) == multiset(s2_left) + multiset([x]) + multiset(s2_right);
            assert multiset(remaining2) == multiset(s2_left) + multiset(s2_right);

            // From multiset(s1) == multiset(s2):
            // multiset([x]) + multiset(remaining1) == multiset(s2_left) + multiset([x]) + multiset(s2_right)
            // multiset([x]) + multiset(remaining1) == multiset([x]) + multiset(remaining2)
            var mx := multiset([x]);
            var mr1 := multiset(remaining1);
            var mr2 := multiset(remaining2);
            assert mx + mr1 == mx + mr2;
            // Help Dafny cancel: for any element e, (mx + mr1)[e] == (mx + mr2)[e] implies mr1[e] == mr2[e]
            forall e: int
