        assert !IsEmpty(pq.left);
        DeleteMinCorrect(pq.left);
        var dm := DeleteMin(pq.left);
        assert Valid(dm);
        assert Elements(dm) + multiset{pq.left.x} == Elements(pq.left);
        // Validity: IsBinaryHeap
        assert pq.left.x <= pq.right.x;
        assert IsBinaryHeap(pq.right);
        assert IsBinaryHeap(dm);
        // pq.left.x <= dm root (if any)
        if dm.Node? {
            BinaryHeapStoresMin(pq.left, dm.x);
            assert pq.left.x <= dm.x;
        }
        assert IsBinaryHeap(pq');
        // IsBalanced: sizes
        assert IsBalanced(pq.right);
        assert IsBalanced(dm);
        assert IsBalanced(pq');
        // Elements
        calc {
            Elements(pq') + multiset{pq.x};
        ==
            (multiset{pq.left.x} + Elements(pq.right) + Elements(dm)) + multiset{pq.x};
        ==
            (Elements(dm) + multiset{pq.left.x}) + Elements(pq.right) + multiset{pq.x};
        ==
            Elements(pq.left) + Elements(pq.right) + multiset{pq.x};
        ==
            Elements(pq);
        }
    } else {
        // pq.left.x > pq.right.x
        // DeleteMin returns Node(pq.right.x, ReplaceRoot(pq.right, pq.left.x), DeleteMin(pq.left))
        var rr := ReplaceRoot(pq.right, pq.left.x);
        var dm := DeleteMin(pq.left);
        assert pq' == Node(pq.right.x, rr, dm);
        DeleteMinCorrect(pq.left);
        ReplaceRootCorrect(pq.right, pq.left.x);
        // Heap ordering
        assert pq.right.x < pq.left.x;
        // pq.right.x <= rr.x (if any)
        if rr.Node? {
            BinaryHeapStoresMin(rr, rr.x);
            assert pq.left.x in Elements(rr);
            BinaryHeapStoresMin(rr, pq.left.x);
            assert rr.x <= pq.left.x;
            assert pq.x <= pq.right.x;
            BinaryHeapStoresMin(pq, pq.right.x);
            assert pq.right.x >= pq.x;
        }
        // pq.right.x <= dm.x (if any)
        if dm.Node? {
            BinaryHeapStoresMin(pq.left, dm.x);
            assert pq.left.x <= dm.x;
            assert pq.x <= pq.right.x;
            BinaryHeapStoresMin(pq, pq.right.x);
            assert pq.right.x <= dm.x;
        }
        assert IsBinaryHeap(pq');
        assert IsBalanced(pq');
        // Elements
        calc {
            Elements(pq') + multiset{pq.x};
        ==
            (multiset{pq.right.x} + Elements(rr) + Elements(dm)) + multiset{pq.x};
        == 
            (Elements(rr) + multiset{pq.right.x}) + Elements(dm) + multiset{pq.x};
        ==  { assert Elements(pq.right) + multiset{pq.left.x} == Elements(rr) + multiset{pq.right.x}; }
            (Elements(pq.right) + multiset{pq.left.x}) + Elements(dm) + multiset{pq.x};
        ==
            Elements(pq.right) + (Elements(dm) + multiset{pq.left.x}) + multiset{pq.x};
        ==
            Elements(pq.right) + Elements(pq.left) + multiset{pq.x};
        ==
            Elements(pq);
        }
    }
}

