stats.proof_process_CountProject:
match xs
case Nil =>
    match ys {
        case Nil =>
        case Cons(yhd, ytl) =>
            if yhd == p {
                // Project(Nil, p) == Nil, but Project(ys, p) == Cons(yhd, Project(ytl, p)) != Nil
                // This contradicts the precondition
            } else {
                // Project(ys, p) == Project(ytl, p), so Project(Nil, p) == Project(ytl, p)
                CountProject(xs, ytl, p);
            }
    }
case Cons(xhd, xtl) =>
    match ys {
        case Nil =>
            if xhd == p {
                // Project(xs, p) == Cons(xhd, Project(xtl, p)) != Nil == Project(Nil, p)
                // Contradiction
            } else {
                CountProject(xtl, ys, p);
            }
        case Cons(yhd, ytl) =>
            if xhd == p && yhd == p {
                CountProject(xtl, ytl, p);
            } else if xhd == p && yhd != p {
                CountProject(xs, ytl, p);
            } else if xhd != p && yhd == p {
                CountProject(xtl, ys, p);
            } else {
                CountProject(xtl, ytl, p);
            }
    }

