stats.proof_process_BijectivityImpliesEqualCar:
if |setA| == 0 {
      assert setA == {};
      if |setB| > 0 {
        var b :| b in setB;
        var a :| a in setA && (a, b) in relation;
      }
      assert |setB| == 0;
    } else {
      var a :| a in setA;
      var b :| b in setB && (a, b) in relation;
      var setA' := setA - {a};
      var setB' := setB - {b};

      // Totality on setA': for every a' in setA', its partner b' is in setB' (not b, by injectivity)
      forall a' | a' in setA'
        ensures exists b' :: b' in setB' && (a', b') in relation
      {
        var b' :| b' in setB && (a', b') in relation;
        // b' != b because if b' == b, then (a, b) in relation and (a', b) in relation with a != a'
        // contradicts injectivity
        assert a' != a;
        if b' == b {
          assert (a, b) in relation && (a', b) in relation;
          assert a == a'; // by injectivity -- contradiction
        }
        assert b' != b;
        assert b' in setB';
      }

      // Injectivity: inherited directly (subset reasoning)
      // Functionality: inherited directly (subset reasoning)

      // Surjectivity onto setB': for every b' in setB', its partner a' is in setA' (not a, by functionality)
      forall b' | b' in setB'
        ensures exists a' :: a' in setA' && (a', b') in relation
      {
        var a' :| a' in setA && (a', b') in relation;
        assert b' != b;
        if a' == a {
          assert (a, b') in relation && (a, b) in relation;
          assert b' == b; // by functionality -- contradiction
        }
        assert a' != a;
        assert a' in setA';
      }

      BijectivityImpliesEqualCardinality(setA', setB', relation);
      assert |setA'| == |setB'|;
      assert |setA| == |setA'| + 1;
      assert |setB| == |setB'| + 1;
    }

stats.proof_process_CrossProductCardinality:
if |setA| == 0 {
      assert setA == {};
      assert cp == {};
    } else {
      var x :| x in setA;
      var setA' := setA - {x};
      var cp' := set a, b | a in setA' && b in setB :: (a, b);
      var line := set a, b | a in {x} && b in setB :: (a, b);

      // Prove line cardinality equals |setB| using bijection
      var relation: iset<((A, B), B)> := iset p: ((A, B), B) | p.0.1 == p.1;

      // Surjectivity: every b in setB has a corresponding pair in line
      forall b | b in setB
        ensures exists p :: p in line && (p, b) in relation
      {
        assert (x, b) in line;
        assert ((x, b), b) in relation;
      }

      // Totality: every element of line maps to something in setB
      forall p | p in line
        ensures exists b :: b in setB && (p, b) in relation
      {
        assert p.1 in setB;
        assert (p, p.1) in relation;
      }

      BijectivityImpliesEqualCardinality(line, setB, relation);
      assert |line| == |setB|;

      // Recursive call for the smaller cross product
      CrossProductCardinality(setA', setB, cp');
      assert |cp'| == |setA'| * |setB|;

      // Prove cp == cp' + line
      assert cp == cp' + line by {
        forall p | p in cp
          ensures p in cp' || p in line
        {
          if p.0 == x {
            assert p.0 in {x} && p.1 in setB;
            assert p in line;
          } else {
            assert p.0 in setA' && p.1 in setB;
            assert p in cp';
          }
        }
        forall p | p in cp' + line
          ensures p in cp
        {
          if p in cp' {
            assert p.0 in setA' && p.1 in setB;
            assert p.0 in setA;
            assert p in cp;
          } else {
            assert p in line;
            assert p.0 in {x} && p.1 in setB;
            assert p.0 == x;
            assert x in setA;
            assert p in cp;
          }
        }
      }

      // Prove disjointness
      assert cp' !! line by {
        forall p | p in cp' && p in line
          ensures false
        {
          assert p.0 in setA';
          assert p.0 in {x};
          assert p.0 == x;
          assert x !in setA';
        }
      }

      // Now combine
      assert |cp| == |cp'| + |line|;

      calc {
        |cp|;
        == |cp'| + |line|;
        == |setA'| * |setB| + |setB|;
        == (|setA| - 1) * |setB| + |setB|;
        == |setA| * |setB|;
      }
    }

